      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projects = [];

function createProject(projectData) {
  const project = { id: generateId(), ...projectData };
  if (projects.some(p => p.name === project.name)) {
    throw { code: 'duplicate', message: 'Project already exists' };
  }
  projects.push(project);
  return project;
}

function getAllProjects() {
  return projects;
}

module.exports = { createProject, getAllProjects };
