      "content": "const { generateId } = require('../../lib/id');
let membersByProject = {};

function addMember(projectId, memberData) {
  if (!membersByProject[projectId]) {
    membersByProject[projectId] = [];
  }
  const member = { id: generateId(), ...memberData };
  if (membersByProject[projectId].some(m => m.userId === member.userId)) {
    throw { code: 'duplicate', message: 'Member already exists in this project' };
  }
  membersByProject[projectId].push(member);
  return member;
}

function getAllMembers(projectId) {
  return membersByProject[projectId] || [];
}

module.exports = { addMember, getAllMembers };
