      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');
let tasksByProject = {};

function createTask(projectId, taskData) {
  if (!tasksByProject[projectId]) {
    tasksByProject[projectId] = [];
  }
  const task = { id: generateId(), status: 'open', ...taskData };
  tasksByProject[projectId].push(task);
  return task;
}

function getAllTasks(projectId, status) {
  if (!tasksByProject[projectId]) {
    return [];
  }
  return status ? tasksByProject[projectId].filter(t => t.status === status) : tasksByProject[projectId];
}

function updateTask(projectId, taskId, taskData) {
  const tasks = tasksByProject[projectId] || [];
  const taskIndex = tasks.findIndex(t => t.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'not_found', message: 'Task not found' };
  }
  tasks[taskIndex] = { ...tasks[taskIndex], ...taskData };
  return tasks[taskIndex];
}

module.exports = { createTask, getAllTasks, updateTask };
