      "content": "const { generateId } = require('../../lib/id');
let commentsByTask = {};

function addComment(projectId, taskId, commentData) {
  const key = `${projectId}-${taskId}`;
  if (!commentsByTask[key]) {
    commentsByTask[key] = [];
  }
  const comment = { id: generateId(), ...commentData };
  commentsByTask[key].push(comment);
  return comment;
}

function getAllComments(projectId, taskId) {
  const key = `${projectId}-${taskId}`;
  return commentsByTask[key] || [];
}

module.exports = { addComment, getAllComments };
